INSERT INTO Ubicacion (Id, Nombre, Tipo, ParentId, Descripcion, Latitud, Longitud) VALUES (30, 'Espejo', 'Canton', 12, 'Canton de Carchi cuya cabecera es El Angel y desde donde se accede a la reserva.', NULL, NULL);
