INSERT INTO Ubicacion (Id, Nombre, Tipo, ParentId, Descripcion, Latitud, Longitud) VALUES (32, 'Reserva Ecológica El Ángel', 'Sitio', 31, 'Reserva de paramo con frailejones, humedales y senderos de altura.', 0.754722, -77.894722);
