INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (3, 'La cascada del silencio ', 'Cascada tranquila ubicada en el sector de Ulba, cerca de Baños de Agua Santa. Destaca por su ambiente natural, caminata corta y paisaje de bosque humedo andino.', 'Senderismo, fotografia, observacion de cascadas, turismo de naturaleza', 5, 'Activo', '2026-03-09 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (4, 'El manto de la novia', 'Cascada de la Ruta de las Cascadas de Baños, reconocida por su caida blanca que recuerda al velo de una novia y por la tarabita panoramica del sector.', 'Tarabita, fotografia, senderismo, observacion de paisajes', 3, 'Activo', '2026-06-07 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (5, 'Cascada de Peguche', 'Hermosa cascada de 18 metros de altura rodeada por un bosque natural. Es considerada un lugar sagrado para las comunidades indígenas de la zona.', 'Senderismo, fotografía, observación de flora y fauna, turismo cultural', 15, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (6, 'Laguna de Quilotoa', 'Laguna volcánica de aguas turquesas ubicada dentro del cráter del volcán Quilotoa.', 'Caminatas, kayak, fotografía y observación de paisajes', 18, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (7, 'Cueva de los Tayos', 'Sistema de cuevas reconocido por sus impresionantes formaciones rocosas y biodiversidad.', 'Exploración, senderismo y observación de fauna', 20, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (8, 'Bosque Protector Mindo Nambillo', 'Bosque nublado con gran diversidad de aves, mariposas y cascadas.', 'Canopy, senderismo, observación de aves y ciclismo', 23, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (9, 'Cerro Puñay', 'Montaña con una pirámide arqueológica en la cima y espectaculares vistas panorámicas.', 'Senderismo, camping y fotografía', 26, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (10, 'Playa Los Frailes', 'Considerada una de las playas más hermosas del Ecuador por sus aguas cristalinas y entorno natural.', 'Natación, caminatas y observación de paisajes', 29, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (11, 'Reserva Ecológica El Ángel', 'Reserva famosa por sus frailejones gigantes y ecosistemas de páramo únicos.', 'Senderismo, observación de flora y fotografía', 32, 'Activo', '2026-06-10 00:00:00');
INSERT INTO Sitio (Id, Nombre, Descripcion, Actividades, UbicacionId, Estado, FechaCreacion) VALUES (12, 'Complejo Lacustre de Ozogoche', 'Conjunto de lagunas rodeadas por páramos andinos y leyendas ancestrales.', 'Observación de aves, senderismo y fotografía', 35, 'Activo', '2026-06-10 00:00:00');
